mapper.insert:
SELECT ISS_SEQ.NEXTVAL FROM DUAL
INSERT INTO ISSUE ( ID, PRJ_ID, SUBJECT, DESCRIPTION, CATEGORY_CD, PRIORITY_CD, CREATED_ON, UPDATED_ON, EST_START_DATE, DUE_DATE, START_DATE, CLOSED_DATE, PARENT_ISSUE, ROOT_ISSUE, MEM_ID, LFT, RGT, DONE_RATIO
, IS_ATTACH_CD
) VALUES ( #{id}, 3, #{subject}, #{description}, #{categoryCd}, #{priorityCd}, SYSDATE, #{updatedOn}, #{estStartDate}, #{dueDate}, #{startDate}, #{closedDate}, #{parentIssue}, #{rootIssue}, #{memId}, #{lft}, #{rgt}, #{doneRatio}
,#{isAttachCd}
)

mapper.update:
UPDATE ISSUE
SUBJECT = #{subject}, DESCRIPTION = #{description}, CATEGORY_CD = #{categoryCd}, STATUS_CD = #{statusCd}, PRIORITY_CD = #{priorityCd}, EST_START_DATE = #{estStartDate}, DUE_DATE = #{dueDate}, START_DATE = #{startDate}, CLOSED_DATE = #{closedDate}, ROOT_ISSUE = #{rootIssue}, MEM_ID = #{memId}, LFT = #{lft}, RGT = #{rgt}, DONE_RATIO = #{doneRatio}, IS_ATTACH_CD = #{isAttachCd}, UPDATED_ON = SYSDATE
WHERE ID = #{id}

mapper.select:
SELECT COUNT(*)
FROM ISSUE
WHERE PARENT_ISSUE = #{id}

SELECT id,subject
FROM ISSUE
WHERE id = #{id}
